#[test]
fn decodes_plain_hex_and_sql_hex() {
    assert_eq!(decode_hex("efbbbf").unwrap(), vec![0xef, 0xbb, 0xbf]);
    assert_eq!(decode_hex("0x0102ff").unwrap(), vec![1, 2, 255]);
}

#[test]
fn rejects_odd_hex_length() {
    assert!(decode_hex("abc").is_err());
}

#[test]
fn extracts_json_array_from_sqlcmd_noise() {
    let stdout = "Changed database context.\r\n[{\"a\":1}]\r\n(1 row affected)";
    assert_eq!(extract_json_array(stdout, "test").unwrap(), r#"[{"a":1}]"#);
}

#[test]
fn normalizes_wrapped_sqlcmd_json() {
    let stdout = "Changed database context.\r\n[{\"binary_hex\":\"AABB\r\nCCDD\"}]\r\n";
    let json = extract_json_array(stdout, "test").unwrap();
    let normalized = normalize_sqlcmd_json(&json);
    let rows: Vec<serde_json::Value> = serde_json::from_str(&normalized).unwrap();

    assert_eq!(rows[0]["binary_hex"], "AABBCCDD");
}

#[test]
fn fetch_rows_sql_chunks_large_binary_values() {
    let selected = BTreeSet::from(["aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa".to_string()]);
    let sql = build_fetch_rows_sql("TestDb", "Config", &selected);

    assert!(sql.contains("DECLARE @chunk_size int = 16384"));
    assert!(sql.contains("FROM [TestDb].dbo.[Config]"));
    assert!(sql.contains("SUBSTRING(rows.BinaryData"));
    assert!(sql.contains("chunks.chunk_index * @chunk_size + 1"));
    assert!(sql.contains("WHERE FileName IN (N'aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa')"));
    assert!(sql.contains("ORDER BY rows.FileName, rows.PartNo, chunks.chunk_index"));
    assert!(!sql.contains("FOR JSON"));
}

#[test]
fn fetch_rows_direct_hex_sql_skips_chunk_cross_apply() {
    let selected = BTreeSet::from(["aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa".to_string()]);
    let sql = build_fetch_rows_direct_hex_sql("TestDb", "Config", &selected);

    assert!(sql.contains("FROM [TestDb].dbo.[Config]"));
    assert!(sql.contains("CONVERT(varchar(max), BinaryData, 2) AS binary_hex"));
    assert!(sql.contains("WHERE FileName IN (N'aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa')"));
    assert!(!sql.contains("CROSS APPLY"));
    assert!(!sql.contains("sys.all_objects"));
}

#[test]
fn fetch_binary_rows_query_can_use_range_filter() {
    let selected = BTreeSet::from([
        "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa".to_string(),
        "bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb".to_string(),
    ]);

    let sql = build_fetch_binary_rows_query("TestDb", "Config", &selected, true);

    assert!(sql.contains("FROM [TestDb].dbo.[Config]"));
    assert!(sql.contains(
            "WHERE FileName >= N'aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa' AND FileName <= N'bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb'"
        ));
    assert!(!sql.contains(" IN "));
    assert!(sql.contains("ORDER BY FileName, PartNo"));
}

#[test]
fn fetch_binary_rows_query_selected_exact_filter_uses_in() {
    let selected = BTreeSet::from([
        "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa".to_string(),
        "bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb".to_string(),
    ]);

    let sql = build_fetch_binary_rows_query("TestDb", "Config", &selected, false);

    assert!(sql.contains("FROM [TestDb].dbo.[Config]"));
    assert!(sql.contains(
            "WHERE FileName IN (N'aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa', N'bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb')"
        ));
    assert!(!sql.contains("FileName >="));
    assert!(sql.contains("ORDER BY FileName, PartNo"));
}

#[test]
fn fetch_metadata_rows_bcp_query_filters_body_rows() {
    let sql = build_fetch_metadata_rows_bcp_query("TestDb", "Config");

    assert!(sql.contains("FROM [TestDb].dbo.[Config]"));
    assert!(sql.contains("WHERE CHARINDEX(N'.', FileName) = 0"));
    assert!(sql.contains("ORDER BY FileName, PartNo"));
}

#[test]
fn converts_binary_rows_to_config_rows() {
    let row = config_row_from_binary(BinaryConfigRow {
        file_name: "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa".to_string(),
        part_no: 0,
        data_size: 3,
        binary: vec![0xef, 0xbb, 0xbf],
    });

    assert_eq!(row.binary_hex, "efbbbf");
}

#[test]
fn converts_binary_rows_to_config_rows_with_lowercase_hex() {
    let rows = config_rows_from_binary(vec![
        BinaryConfigRow {
            file_name: "first".to_string(),
            part_no: 0,
            data_size: 2,
            binary: vec![0xaa, 0xbb],
        },
        BinaryConfigRow {
            file_name: "second".to_string(),
            part_no: 0,
            data_size: 1,
            binary: vec![0xcc],
        },
    ]);

    assert_eq!(rows.len(), 2);
    assert_eq!(rows[0].file_name, "first");
    assert_eq!(rows[0].binary_hex, "aabb");
    assert_eq!(rows[1].file_name, "second");
    assert_eq!(rows[1].binary_hex, "cc");
}

#[test]
fn timing_report_add_assign_keeps_sqlcmd_bcp_breakdown() {
    let mut total = MssqlDumpTimingReport {
        fetch_headers_ms: 10,
        fetch_headers_sqlcmd_ms: 10,
        prepare_metadata_fetch_ms: 20,
        prepare_metadata_fetch_sqlcmd_ms: 3,
        prepare_metadata_fetch_bcp_ms: 17,
        fetch_rows_ms: 30,
        fetch_rows_bcp_ms: 30,
        fetch_row_batches: 2,
        fetch_row_batch_max_rows: 5,
        fetch_row_batch_max_binary_bytes: 100,
        ..MssqlDumpTimingReport::default()
    };
    let next = MssqlDumpTimingReport {
        fetch_headers_ms: 1,
        fetch_headers_sqlcmd_ms: 1,
        prepare_metadata_fetch_ms: 2,
        prepare_metadata_fetch_sqlcmd_ms: 0,
        prepare_metadata_fetch_bcp_ms: 2,
        fetch_rows_ms: 3,
        fetch_rows_bcp_ms: 3,
        fetch_row_batches: 1,
        fetch_row_batch_max_rows: 9,
        fetch_row_batch_max_binary_bytes: 50,
        ..MssqlDumpTimingReport::default()
    };

    total.add_assign(&next);

    assert_eq!(total.fetch_headers_ms, 11);
    assert_eq!(total.fetch_headers_sqlcmd_ms, 11);
    assert_eq!(total.prepare_metadata_fetch_ms, 22);
    assert_eq!(total.prepare_metadata_fetch_sqlcmd_ms, 3);
    assert_eq!(total.prepare_metadata_fetch_bcp_ms, 19);
    assert_eq!(total.fetch_rows_ms, 33);
    assert_eq!(total.fetch_rows_bcp_ms, 33);
    assert_eq!(total.fetch_row_batches, 3);
    assert_eq!(total.fetch_row_batch_max_rows, 9);
    assert_eq!(total.fetch_row_batch_max_binary_bytes, 100);
}

#[test]
fn dump_timing_summary_extracts_batch_followup_fields() {
    let half_gib = 512 * 1024 * 1024usize;
    let report = MssqlDumpConfigReport {
        database: "PerfDb".to_string(),
        output_dir: PathBuf::from(r"E:\ibcmd_lab\perf\full"),
        tables: vec![MssqlDumpedTableReport {
            table: "Config".to_string(),
            rows: 12,
            binary_bytes: half_gib,
            inflated_rows: 0,
            module_text_rows: 0,
            metadata_xml_rows: 0,
            source_asset_rows: 8,
            timings: MssqlDumpTimingReport {
                prepare_indexes_ms: 40,
                prepare_metadata_fetch_ms: 11,
                prepare_metadata_texts_ms: 12,
                prepare_reference_indexes_ms: 13,
                prepare_command_refs_ms: 14,
                fetch_rows_ms: 1000,
                fetch_rows_bcp_ms: 900,
                fetch_row_batches: 2,
                fetch_row_batch_max_rows: 7,
                fetch_row_batch_max_binary_bytes: 300 * 1024 * 1024,
                process_rows_wall_ms: 2000,
                source_asset_cpu_ms: 123,
                source_asset_form_cpu_ms: 80,
                source_asset_inflated_cpu_ms: 30,
                source_asset_help_cpu_ms: 13,
                source_asset_form_xml_cpu_ms: 70,
                source_asset_form_child_items_cpu_ms: 50,
                source_asset_form_properties_cpu_ms: 10,
                ..MssqlDumpTimingReport::default()
            },
        }],
        total_rows: 12,
        total_binary_bytes: half_gib,
        total_inflated_rows: 0,
        total_module_text_rows: 0,
        total_metadata_xml_rows: 0,
        total_source_asset_rows: 8,
        timings: MssqlDumpTimingReport {
            prepare_indexes_ms: 40,
            prepare_metadata_fetch_ms: 11,
            prepare_metadata_fetch_bcp_ms: 11,
            prepare_metadata_texts_ms: 12,
            prepare_reference_indexes_ms: 13,
            prepare_command_refs_ms: 14,
            fetch_rows_ms: 1000,
            fetch_rows_bcp_ms: 900,
            fetch_row_batches: 2,
            fetch_row_batch_max_rows: 7,
            fetch_row_batch_max_binary_bytes: 300 * 1024 * 1024,
            process_rows_wall_ms: 2000,
            source_asset_cpu_ms: 123,
            source_asset_form_cpu_ms: 80,
            source_asset_inflated_cpu_ms: 30,
            source_asset_help_cpu_ms: 13,
            source_asset_form_xml_cpu_ms: 70,
            source_asset_form_child_items_cpu_ms: 50,
            source_asset_form_properties_cpu_ms: 10,
            ..MssqlDumpTimingReport::default()
        },
    };
    let json = serde_json::to_string(&report).unwrap();

    let summary = parse_dump_timing_summary(&json, Some(PathBuf::from("report.json"))).unwrap();

    assert_eq!(summary.report_path, Some(PathBuf::from("report.json")));
    assert_eq!(summary.database, "PerfDb");
    assert_eq!(summary.batch_cap_binary_bytes, 256 * 1024 * 1024);
    assert_eq!(summary.fetch_row_batches, 2);
    assert_eq!(summary.fetch_row_batch_max_rows, 7);
    assert_eq!(summary.fetch_row_batch_max_binary_mib, 300);
    assert_eq!(summary.fetch_rows_ms_per_gib, Some(2000));
    assert_eq!(summary.process_rows_wall_ms_per_gib, Some(4000));
    assert_eq!(summary.source_asset_cpu_ms, 123);
    assert_eq!(summary.source_asset_cpu_ms_per_row, Some(15));
    assert_eq!(summary.source_asset_cpu_breakdown[0].metric, "form");
    assert_eq!(summary.source_asset_cpu_breakdown[0].cpu_ms, 80);
    assert_eq!(summary.source_asset_cpu_breakdown[1].metric, "inflated");
    assert_eq!(summary.form_cpu_breakdown[0].metric, "form_xml");
    assert_eq!(summary.form_cpu_breakdown[1].metric, "child_items");
    assert_eq!(summary.tables[0].table, "Config");
    assert_eq!(summary.tables[0].fetch_row_batch_max_binary_mib, 300);
    assert_eq!(summary.tables[0].source_asset_cpu_ms_per_row, Some(15));
}

#[test]
fn dump_timing_summary_defaults_missing_new_timing_fields() {
    let json = r#"{
            "database": "OldReport",
            "output_dir": "E:\\ibcmd_lab\\perf\\old",
            "tables": [{
                "table": "Config",
                "rows": 1,
                "binary_bytes": 0,
                "inflated_rows": 0,
                "module_text_rows": 0,
                "metadata_xml_rows": 0,
                "source_asset_rows": 0,
                "timings": {"fetch_rows_ms": 5}
            }],
            "total_rows": 1,
            "total_binary_bytes": 0,
            "total_inflated_rows": 0,
            "total_module_text_rows": 0,
            "total_metadata_xml_rows": 0,
            "total_source_asset_rows": 0,
            "timings": {"fetch_rows_ms": 5}
        }"#;

    let summary = parse_dump_timing_summary(json, None).unwrap();

    assert_eq!(summary.fetch_rows_ms, 5);
    assert_eq!(summary.fetch_row_batches, 0);
    assert_eq!(summary.fetch_row_batch_max_binary_bytes, 0);
    assert_eq!(summary.fetch_rows_ms_per_gib, None);
    assert_eq!(summary.source_asset_cpu_ms_per_row, None);
    assert!(summary.source_asset_cpu_breakdown.is_empty());
    assert!(summary.form_cpu_breakdown.is_empty());
}

#[test]
fn parses_native_bcp_rows_and_assembles_parts() {
    let mut bytes = Vec::new();
    push_native_bcp_row(&mut bytes, "first", 0, 5, b"abc");
    push_native_bcp_row(&mut bytes, "first", 1, 5, b"de");
    push_native_bcp_row(&mut bytes, "second", 0, 1, b"z");

    let parts = parse_bcp_native_config_rows(&bytes).unwrap();
    let rows = assemble_binary_config_rows(parts).unwrap();

    assert_eq!(rows.len(), 2);
    assert_eq!(rows[0].file_name, "first");
    assert_eq!(rows[0].part_no, 0);
    assert_eq!(rows[0].data_size, 5);
    assert_eq!(rows[0].binary, b"abcde");
    assert_eq!(rows[1].file_name, "second");
    assert_eq!(rows[1].binary, b"z");
}

#[test]
fn dump_file_name_batches_limit_large_blob_memory() {
    let big = SQLCMD_DUMP_BATCH_MAX_DATA_BYTES;
    assert_eq!(big, 256 * 1024 * 1024);
    let headers = vec![
        ConfigRowHeader {
            file_name: "small-1".to_string(),
            part_no: 0,
            data_size: 1024,
        },
        ConfigRowHeader {
            file_name: "large".to_string(),
            part_no: 0,
            data_size: big as i64,
        },
        ConfigRowHeader {
            file_name: "small-2".to_string(),
            part_no: 0,
            data_size: 1024,
        },
    ];
    let file_names = BTreeSet::from([
        "large".to_string(),
        "small-1".to_string(),
        "small-2".to_string(),
    ]);

    let batches = build_dump_file_name_batches(&headers, &file_names);

    assert_eq!(
        batches,
        vec![
            vec!["large".to_string()],
            vec!["small-1".to_string(), "small-2".to_string()]
        ]
    );
}

#[test]
fn parses_config_chunk_rows_from_sqlcmd_tsv() {
    let rows = parse_config_chunk_rows(
        "file_name\tpart_no\tdata_size\tchunk_index\tbinary_hex\r\n\
             ---------\t-------\t---------\t-----------\t----------\r\n\
             large   \t0\t4\t0\tAABB   \r\n\
             large\t0\t4\t1\tCCDD\r\n",
    )
    .unwrap();

    assert_eq!(rows.len(), 2);
    assert_eq!(rows[0].file_name, "large");
    assert_eq!(rows[0].part_no, 0);
    assert_eq!(rows[0].data_size, 4);
    assert_eq!(rows[0].chunk_index, 0);
    assert_eq!(rows[0].binary_hex, "AABB");
    assert_eq!(rows[1].chunk_index, 1);
    assert_eq!(rows[1].binary_hex, "CCDD");
}

#[test]
fn parses_config_direct_rows_from_sqlcmd_tsv() {
    let rows = parse_config_direct_rows(
        "file_name\tpart_no\tdata_size\tbinary_hex\r\n\
             ---------\t-------\t---------\t----------\r\n\
             first   \t0\t3\tAABBCC   \r\n\
             second\t0\t1\tDD\r\n",
    )
    .unwrap();

    assert_eq!(rows.len(), 2);
    assert_eq!(rows[0].file_name, "first");
    assert_eq!(rows[0].part_no, 0);
    assert_eq!(rows[0].data_size, 3);
    assert_eq!(rows[0].binary_hex, "aabbcc");
    assert_eq!(rows[1].file_name, "second");
    assert_eq!(rows[1].binary_hex, "dd");
}

#[test]
fn assembles_config_rows_from_ordered_chunks() {
    let rows = assemble_config_rows(vec![
        ConfigChunkRow {
            file_name: "large".to_string(),
            part_no: 0,
            data_size: 4,
            chunk_index: 0,
            binary_hex: "AABB".to_string(),
        },
        ConfigChunkRow {
            file_name: "large".to_string(),
            part_no: 0,
            data_size: 4,
            chunk_index: 1,
            binary_hex: "CCDD".to_string(),
        },
        ConfigChunkRow {
            file_name: "small".to_string(),
            part_no: 0,
            data_size: 1,
            chunk_index: 0,
            binary_hex: "EE".to_string(),
        },
    ])
    .unwrap();

    assert_eq!(rows.len(), 2);
    assert_eq!(rows[0].file_name, "large");
    assert_eq!(rows[0].binary_hex, "AABBCCDD");
    assert_eq!(rows[1].file_name, "small");
    assert_eq!(rows[1].binary_hex, "EE");
}

#[test]
fn assembles_config_rows_from_multiple_physical_parts() {
    let rows = assemble_config_rows(vec![
        ConfigChunkRow {
            file_name: "large".to_string(),
            part_no: 0,
            data_size: 4,
            chunk_index: 0,
            binary_hex: "AABB".to_string(),
        },
        ConfigChunkRow {
            file_name: "large".to_string(),
            part_no: 1,
            data_size: 4,
            chunk_index: 0,
            binary_hex: "CCDD".to_string(),
        },
    ])
    .unwrap();

    assert_eq!(rows.len(), 1);
    assert_eq!(rows[0].file_name, "large");
    assert_eq!(rows[0].part_no, 0);
    assert_eq!(rows[0].data_size, 4);
    assert_eq!(rows[0].binary_hex, "AABBCCDD");
}

#[test]
fn rejects_config_row_chunk_order_gaps() {
    let err = assemble_config_rows(vec![ConfigChunkRow {
        file_name: "large".to_string(),
        part_no: 0,
        data_size: 4,
        chunk_index: 1,
        binary_hex: "AABB".to_string(),
    }])
    .unwrap_err();

    assert!(err.to_string().contains("chunk order gap"));
}

