#[test]
fn extracts_configuration_xml_with_generic_root_child_families() {
    let uuid = "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
    let header_uuid = "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb";
    let zero_uuid = "00000000-0000-0000-0000-000000000000";
    let language_uuid = "11111111-1111-4111-8111-111111111111";
    let package_uuid = "22222222-2222-4222-8222-222222222222";
    let storage_uuid = "33333333-3333-4333-8333-333333333333";
    let job_uuid = "44444444-4444-4444-8444-444444444444";
    let group_uuid = "55555555-5555-4555-8555-555555555555";
    let style_uuid = "66666666-6666-4666-8666-666666666666";
    let numerator_uuid = "77777777-7777-4777-8777-777777777777";
    let fields = vec![
            "68".to_string(),
            r#"{0,{3,{1,0,@HEADER_UUID@},"Root",{1,"en","Root"},"",0,0,@ZERO_UUID@,0}}"#
                .replace("@HEADER_UUID@", header_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
            r#"{0,{3,{1,0,@LANGUAGE_UUID@},"Lang",{1,"en","Lang"},"",0,0,@ZERO_UUID@,0},"en"}"#
                .replace("@LANGUAGE_UUID@", language_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
            r#"{1,{3,{1,0,@PACKAGE_UUID@},"Package",{1,"en","Package"},"",0,0,@ZERO_UUID@,0},"http://example.invalid/package"}"#
                .replace("@PACKAGE_UUID@", package_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
            r#"{2,{0,{3,{1,0,@STORAGE_UUID@},"UserSettings",{1,"en","User settings"},"",0,0,@ZERO_UUID@,0}},@ZERO_UUID@,@ZERO_UUID@,@ZERO_UUID@,@ZERO_UUID@,@ZERO_UUID@,@ZERO_UUID@},2,{0},{0}}"#
                .replace("@STORAGE_UUID@", storage_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
            r#"{2,{3,{1,0,@JOB_UUID@},"LoadRates",{1,"en","Load rates"},"",0,0,@ZERO_UUID@,0},"","Load rates",1,1,@ZERO_UUID@,"LoadRates",3,10}"#
                .replace("@JOB_UUID@", job_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
            r#"{3,{4,1,{0,@ZERO_UUID@},"",-1,-1,0,0,""},8,1,{0},{0},{3,{1,0,@GROUP_UUID@},"Admin",{1,"en","Admin"},"",0,0,@ZERO_UUID@,0}}"#
                .replace("@GROUP_UUID@", group_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
            r#"{3,{3,{1,0,@STYLE_UUID@},"Main",{1,"en","Main"},"",0,0,@ZERO_UUID@,0}}"#
                .replace("@STYLE_UUID@", style_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
            r#"{3,{3,{1,0,@NUMERATOR_UUID@},"Numbers",{1,"en","Numbers"},"",0,0,@ZERO_UUID@,0},1,11,1,1,0}"#
                .replace("@NUMERATOR_UUID@", numerator_uuid)
                .replace("@ZERO_UUID@", zero_uuid),
        ];
    let plain = format!(
        "{{2,{{{uuid}}},1,{{9cd510cd-abfc-11d4-9434-004095e12fc7,{{1,{{{}}}}}}}}}",
        fields.join(",")
    );
    let blob = deflate_for_test(plain.as_bytes());

    for source_version in [
        InfobaseConfigSourceVersion::V2_20,
        InfobaseConfigSourceVersion::V2_21,
    ] {
        let extracted = extract_metadata_source_xml_with_refs(
            &blob,
            uuid,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            source_version,
        )
        .unwrap();
        let xml = String::from_utf8_lossy(&extracted.xml);

        assert_eq!(extracted.relative_path, PathBuf::from("Configuration.xml"));
        assert!(xml.contains(&format!(r#"version="{}""#, source_version.as_str())));
        assert!(
            xml.contains(&format!(r#"<Language uuid="{language_uuid}">"#)),
            "{xml}"
        );
        assert!(xml.contains(&format!(r#"<XDTOPackage uuid="{package_uuid}">"#)));
        assert!(xml.contains(&format!(r#"<SettingsStorage uuid="{storage_uuid}">"#)));
        assert!(xml.contains(&format!(r#"<ScheduledJob uuid="{job_uuid}">"#)));
        assert!(xml.contains(&format!(r#"<CommandGroup uuid="{group_uuid}">"#)));
        assert!(xml.contains(&format!(r#"<Style uuid="{style_uuid}">"#)));
        assert!(xml.contains(&format!(r#"<DocumentNumerator uuid="{numerator_uuid}">"#)));
        assert!(!xml.contains(header_uuid));
        assert!(!xml.contains("ConfigDumpInfo"));
    }
}

#[test]
fn extracts_constant_xml_from_metadata_blob() {
    let uuid = "dddddddd-dddd-4ddd-dddd-dddddddddddd";
    let blob = deflate_for_test(
            format!(
                "{{1,\r\n{{16,\r\n{{27,\r\n{{2,\r\n{{3,\r\n{{1,0,{uuid}}},\"UseFeature\",{{1,\"en\",\"Use feature\"}},\"Feature flag\",0,0,00000000-0000-0000-0000-000000000000,0}},{{\"Pattern\",{{\"B\"}}}}\r\n}},0,\r\n{{0}},\r\n{{1,\"en\",\"Use feature tip\"}},0,\"\",0,\r\n{{\"U\"}},\r\n{{\"U\"}},0,00000000-0000-0000-0000-000000000000,2,0,\r\n{{5006,0}},\r\n{{3,0,0}},\r\n{{0,0}},0,\r\n{{0}},\r\n{{\"S\",\"\"}},0,0,0}},00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000,00000000-0000-0000-0000-000000000000,1,1,\r\n{{0}},1,0}}\r\n}}\r\n}}"
            )
            .as_bytes(),
        );

    let extracted = extract_metadata_source_xml(
        &blob,
        uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
    )
    .unwrap();
    let properties = parse_simple_metadata_xml_properties(&extracted.xml).unwrap();
    let repacked = pack_simple_metadata_blob_from_xml(&blob, &extracted.xml).unwrap();

    assert_eq!(
        extracted.relative_path,
        PathBuf::from("Constants").join("UseFeature.xml")
    );
    assert_eq!(properties.kind, "Constant");
    assert_eq!(properties.uuid, uuid);
    assert_eq!(properties.name, "UseFeature");
    assert_eq!(properties.comment, "Feature flag");
    let xml = String::from_utf8_lossy(&extracted.xml);
    assert!(xml.starts_with('\u{feff}'));
    assert!(xml.contains(r#"xmlns:app="http://v8.1c.ru/8.2/managed-application/core""#));
    assert!(xml.contains(r#"version="2.20""#));
    assert!(
        xml.contains(r#"<xr:GeneratedType name="ConstantManager.UseFeature" category="Manager">"#)
    );
    assert!(xml.contains(
        r#"<xr:GeneratedType name="ConstantValueManager.UseFeature" category="ValueManager">"#
    ));
    assert!(xml.contains("xs:boolean"));
    assert!(xml.contains("<UseStandardCommands>true"));
    assert!(xml.contains("<ToolTip>"));
    assert!(xml.contains("<v8:content>Use feature tip</v8:content>"));
    assert!(xml.contains("<DefaultForm/>"));
    assert!(xml.contains("<DataLockControlMode>Managed</DataLockControlMode>"));
    assert!(xml.contains("<ExecuteAfterWriteDataHistoryVersionProcessing>false</ExecuteAfterWriteDataHistoryVersionProcessing>"));
    assert!(!xml.ends_with("\r\n"));
    assert!(!repacked.blob.is_empty());

    let constant = parse_constant_properties_from_text(
        &String::from_utf8(inflate_raw_deflate(&blob).unwrap()).unwrap(),
        uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
    )
    .unwrap();
    let v21_xml = format_constant_source_xml(
        &MetadataHeader {
            uuid: uuid.to_string(),
            name: "UseFeature".to_string(),
            synonyms: Vec::new(),
            comment: String::new(),
            template_type_code: None,
        },
        &constant,
        InfobaseConfigSourceVersion::V2_21,
    );
    assert!(v21_xml.contains(r#"version="2.21""#));
    assert!(!v21_xml.contains(r#"version="2.20""#));
}

#[test]
fn parses_constant_choice_parameters_as_design_time_refs() {
    let object_refs = BTreeMap::from([(
        "9fe5bd6a-0dc3-492a-8124-5d8374b7dc0f".to_string(),
        "Enum.ТипыИзмеряемыхВеличин.EnumValue.Вес".to_string(),
    )]);
    let parameters = parse_constant_choice_parameters(
        Some(
            r##"{0,1,"Отбор.ТипИзмеряемойВеличины", {"#",5c14e26f-099b-4d37-84a6-b433d87400da,{0,e9aecab4-da2b-4a51-b13c-fb8ca3924bce,9fe5bd6a-0dc3-492a-8124-5d8374b7dc0f}}}"##,
        ),
        &object_refs,
    );

    assert_eq!(parameters.len(), 1);
    assert_eq!(parameters[0].name, "Отбор.ТипИзмеряемойВеличины");
    assert_eq!(
        format_choice_parameters_xml(&parameters),
        "<ChoiceParameters>\r\n\t\t\t\t<app:item name=\"Отбор.ТипИзмеряемойВеличины\">\r\n\t\t\t\t\t<app:value xsi:type=\"xr:DesignTimeRef\">Enum.ТипыИзмеряемыхВеличин.EnumValue.Вес</app:value>\r\n\t\t\t\t</app:item>\r\n\t\t\t</ChoiceParameters>"
    );
}

