#[test]
fn extracts_common_attribute_xml_with_type_from_metadata_blob() {
    let uuid = "33333333-3333-4333-8333-333333333333";
    let catalog_uuid = "44444444-4444-4444-8444-444444444444";
    let plain = format!(
        "{{1,\r\n{{5,\r\n{{27,\r\n{{2,\r\n{{3,\r\n{{1,0,{uuid}}},\"ExternalCode\",{{1,\"en\",\"External code\"}},\"\",0,0,00000000-0000-0000-0000-000000000000,0}},\r\n{{\"Pattern\",{{\"S\",50,1}}}}\r\n}}\r\n}},\r\n{{0,1,\r\n{{{catalog_uuid}}}\r\n}}\r\n}}\r\n}}"
    );
    let blob = deflate_for_test(plain.as_bytes());
    let object_refs = BTreeMap::from([(catalog_uuid.to_string(), "Catalog.Products".to_string())]);

    let extracted = extract_metadata_source_xml_with_refs(
        &blob,
        uuid,
        &BTreeMap::new(),
        &object_refs,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_20,
    )
    .unwrap();
    let properties = parse_simple_metadata_xml_properties(&extracted.xml).unwrap();
    let repacked = pack_simple_metadata_blob_from_xml(&blob, &extracted.xml).unwrap();
    let xml = String::from_utf8_lossy(&extracted.xml);

    assert_eq!(
        extracted.relative_path,
        PathBuf::from("CommonAttributes").join("ExternalCode.xml")
    );
    assert_eq!(properties.kind, "CommonAttribute");
    assert_eq!(properties.uuid, uuid);
    assert!(xml.contains("<v8:Type>xs:string</v8:Type>"));
    assert!(xml.contains("<v8:Length>50</v8:Length>"));
    assert!(xml.contains("<v8:AllowedLength>Variable</v8:AllowedLength>"));
    assert!(xml.contains("<Content>"));
    assert!(xml.contains("<xr:Metadata>Catalog.Products</xr:Metadata>"));
    assert!(xml.contains("<xr:Use>Use</xr:Use>"));
    assert!(xml.contains("<xr:ConditionalSeparation/>"));
    assert!(xml.contains("<AutoUse>DontUse</AutoUse>"));
    assert!(!repacked.blob.is_empty());
    let repacked_plain = String::from_utf8(inflate_raw_deflate(&repacked.blob).unwrap()).unwrap();
    assert_eq!(repacked_plain, plain);

    let extracted_v21 = extract_metadata_source_xml_with_refs(
        &blob,
        uuid,
        &BTreeMap::new(),
        &object_refs,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let xml_v21 = String::from_utf8_lossy(&extracted_v21.xml);
    assert!(xml_v21.contains(r#"version="2.21""#));
    assert!(!xml_v21.contains(r#"version="2.20""#));
}

