#[test]
fn resolves_chart_of_calculation_types_generated_types_in_defined_types() {
    let root = std::env::temp_dir().join(format!(
        "ibcmd-rs-mssql-dump-test-{}",
        uuid::Uuid::new_v4().hyphenated()
    ));
    fs::create_dir_all(&root).unwrap();
    let chart_uuid = "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa";
    let object_type_id = "11111111-1111-4111-8111-000000000101";
    let ref_type_id = "11111111-1111-4111-8111-000000000103";
    let generated_type_ids = (101..=122)
        .map(|suffix| format!("11111111-1111-4111-8111-{suffix:012}"))
        .collect::<Vec<_>>()
        .join(",");
    let chart_blob = deflate_for_test(
        format!(
            "{{1,\r\n{{35,\r\n{{0,\r\n{{3,\r\n{{1,0,{chart_uuid}}},\"PayrollTypes\",{{1,\"en\",\"Payroll types\"}},\"\"\r\n}}\r\n}},{generated_type_ids}\r\n}},0}}"
        )
        .as_bytes(),
    );
    let defined_type_row = |uuid: &str, name: &str, type_id: &str, own_type_seed: &str| {
        let blob = deflate_for_test(
            format!(
                "{{1,\r\n{{0,{own_type_seed},22222222-2222-4222-8222-222222222222,\r\n{{3,\r\n{{1,0,{uuid}}},\"{name}\",{{1,\"en\",\"{name}\"}},\"\"}},\r\n{{\"Pattern\",{{\"#\",{type_id}}}}}\r\n}},0}}"
            )
            .as_bytes(),
        );
        ConfigRow {
            file_name: uuid.to_string(),
            part_no: 0,
            data_size: blob.len() as i64,
            binary_hex: encode_hex_for_test(&blob),
        }
    };
    let rows = vec![
        ConfigRow {
            file_name: chart_uuid.to_string(),
            part_no: 0,
            data_size: chart_blob.len() as i64,
            binary_hex: encode_hex_for_test(&chart_blob),
        },
        defined_type_row(
            "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb",
            "VersionedData",
            ref_type_id,
            "33333333-3333-4333-8333-333333333333",
        ),
        defined_type_row(
            "cccccccc-cccc-4ccc-8ccc-cccccccccccc",
            "VersionedDataObject",
            object_type_id,
            "44444444-4444-4444-8444-444444444444",
        ),
    ];

    dump_table_rows(&root, "Config", rows, false, false, true).unwrap();

    let ref_xml = fs::read_to_string(root.join("DefinedTypes/VersionedData.xml")).unwrap();
    let object_xml = fs::read_to_string(root.join("DefinedTypes/VersionedDataObject.xml")).unwrap();
    assert!(ref_xml.contains("<v8:Type>cfg:ChartOfCalculationTypesRef.PayrollTypes</v8:Type>"));
    assert!(
        object_xml.contains("<v8:Type>cfg:ChartOfCalculationTypesObject.PayrollTypes</v8:Type>")
    );

    let _ = fs::remove_dir_all(root);
}

#[test]
fn extracts_document_generated_types_to_metadata_xml() {
    let document_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let object_type_id = "11111111-1111-4111-8111-111111111111";
    let object_value_id = "11111111-1111-4111-8111-111111111112";
    let ref_type_id = "22222222-2222-4222-8222-222222222221";
    let ref_value_id = "22222222-2222-4222-8222-222222222222";
    let manager_type_id = "33333333-3333-4333-8333-333333333331";
    let manager_value_id = "33333333-3333-4333-8333-333333333332";
    let zero_fields = std::iter::repeat("0")
        .take(20)
        .collect::<Vec<_>>()
        .join(",");
    let document_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{40,{object_type_id},{object_value_id},{ref_type_id},{ref_value_id},\r\n{{0,\r\n{{3,\r\n{{1,0,{document_uuid}}},\"Invoice\",{{1,\"en\",\"Invoice\"}},\"\"}}\r\n}},{zero_fields},{manager_type_id},{manager_value_id}}}\r\n}}"
            )
            .as_bytes(),
        );

    let extracted = extract_metadata_source_xml_with_refs(
        &document_blob,
        document_uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let xml = String::from_utf8(extracted.xml).unwrap();

    assert_eq!(
        extracted.relative_path,
        PathBuf::from("Documents").join("Invoice.xml")
    );
    assert!(xml.starts_with('\u{feff}'));
    assert!(xml.contains(r#"version="2.21""#));
    assert!(
        xml.find("<InternalInfo>").unwrap() < xml.find("<Properties>").unwrap(),
        "{xml}"
    );
    assert!(xml.contains(r#"<xr:GeneratedType name="DocumentObject.Invoice" category="Object">"#));
    assert!(xml.contains(&format!("<xr:TypeId>{object_type_id}</xr:TypeId>")));
    assert!(xml.contains(&format!("<xr:ValueId>{object_value_id}</xr:ValueId>")));
    assert!(xml.contains(r#"<xr:GeneratedType name="DocumentRef.Invoice" category="Ref">"#));
    assert!(xml.contains(&format!("<xr:TypeId>{ref_type_id}</xr:TypeId>")));
    assert!(xml.contains(&format!("<xr:ValueId>{ref_value_id}</xr:ValueId>")));
    assert!(
        xml.contains(r#"<xr:GeneratedType name="DocumentManager.Invoice" category="Manager">"#)
    );
    assert!(xml.contains(&format!("<xr:TypeId>{manager_type_id}</xr:TypeId>")));
    assert!(xml.contains(&format!("<xr:ValueId>{manager_value_id}</xr:ValueId>")));
}

#[test]
fn extracts_document_standard_attributes_to_metadata_xml() {
    let document_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let object_type_id = "11111111-1111-4111-8111-111111111111";
    let object_value_id = "11111111-1111-4111-8111-111111111112";
    let ref_type_id = "22222222-2222-4222-8222-222222222221";
    let ref_value_id = "22222222-2222-4222-8222-222222222222";
    let manager_type_id = "33333333-3333-4333-8333-333333333331";
    let manager_value_id = "33333333-3333-4333-8333-333333333332";
    let zero_uuid = "00000000-0000-0000-0000-000000000000";
    let standard_attribute_details = r##"{1,{1,2,{-3},510405d3-2a0c-4fea-960a-7fee59b32f9b,{14,2,4690ff70-e3fa-4914-9127-6a9acc5fc949,{"#",87024738-fc2a-4436-ada1-df79d395c424,{1,"ru","Дата документа"}},cf4abea3-37b2-11d4-940f-008048da11f9,{"#",87024738-fc2a-4436-ada1-df79d395c424,{1,"ru","Дата"}}},{-2},510405d3-2a0c-4fea-960a-7fee59b32f9b,{14,2,4690ff70-e3fa-4914-9127-6a9acc5fc949,{"#",87024738-fc2a-4436-ada1-df79d395c424,{1,"ru","Номер документа"}},cf4abea3-37b2-11d4-940f-008048da11f9,{"#",87024738-fc2a-4436-ada1-df79d395c424,{1,"ru","Номер"}}}}}"##;
    let document_blob = |number_type: &str| {
        let mut owner_fields = vec![
            "0".to_string(),
            zero_uuid.to_string(),
            number_type.to_string(),
            "11".to_string(),
            "0".to_string(),
            "0".to_string(),
            "1".to_string(),
            "1".to_string(),
        ];
        owner_fields.extend(std::iter::repeat("0".to_string()).take(12));
        let owner_fields = owner_fields.join(",");
        deflate_for_test(
                format!(
                    "{{1,\r\n{{40,{object_type_id},{object_value_id},{ref_type_id},{ref_value_id},\r\n{{0,\r\n{{3,\r\n{{1,0,{document_uuid}}},\"Invoice\",{{1,\"en\",\"Invoice\"}},\"document comment\"}}\r\n}},{owner_fields},{manager_type_id},{manager_value_id},{standard_attribute_details}}}\r\n}}"
                )
                .as_bytes(),
            )
    };

    let extracted = extract_metadata_source_xml_with_refs(
        &document_blob("1"),
        document_uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let xml = String::from_utf8(extracted.xml).unwrap();

    assert_eq!(
        extracted.relative_path,
        PathBuf::from("Documents").join("Invoice.xml")
    );
    assert!(xml.contains("<Comment>document comment</Comment>"));
    assert!(xml.contains("<StandardAttributes>"));
    assert!(xml.contains(r#"<xr:StandardAttribute name="Posted">"#));
    assert!(xml.contains(r#"<xr:StandardAttribute name="Ref">"#));
    assert!(xml.contains(r#"<xr:StandardAttribute name="DeletionMark">"#));
    assert!(xml.contains(r#"<xr:StandardAttribute name="Date">"#));
    assert!(xml.contains(r#"<xr:StandardAttribute name="Number">"#));
    assert!(xml.contains("<v8:content>Дата документа</v8:content>"));
    assert!(xml.contains("<v8:content>Дата</v8:content>"));
    assert!(xml.contains("<v8:content>Номер документа</v8:content>"));
    assert!(xml.contains("<v8:content>Номер</v8:content>"));
    assert!(xml.contains(r#"<xr:FillValue xsi:type="xs:boolean">false</xr:FillValue>"#));
    assert!(
        xml.contains(r#"<xr:FillValue xsi:type="xs:dateTime">0001-01-01T00:00:00</xr:FillValue>"#)
    );
    assert!(xml.contains(r#"<xr:FillValue xsi:type="xs:string"/>"#));
    assert!(
        xml.find("<Comment>document comment</Comment>").unwrap()
            < xml.find("<StandardAttributes>").unwrap(),
        "{xml}"
    );
    assert!(
        xml.find(r#"<xr:StandardAttribute name="Posted">"#)
            < xml.find(r#"<xr:StandardAttribute name="Number">"#),
        "{xml}"
    );

    let numeric = extract_metadata_source_xml_with_refs(
        &document_blob("0"),
        document_uuid,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let numeric_xml = String::from_utf8(numeric.xml).unwrap();

    assert!(!numeric_xml.contains(r#"<xr:FillValue xsi:type="xs:string"/>"#));
    assert!(numeric_xml.contains(r#"<xr:StandardAttribute name="Number">"#));
}

#[test]
fn extracts_document_numbering_commands_and_default_forms_to_metadata_xml() {
    let document_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let numerator_uuid = "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb";
    let object_form_uuid = "cccccccc-cccc-4ccc-8ccc-ccccccccccc1";
    let list_form_uuid = "cccccccc-cccc-4ccc-8ccc-ccccccccccc2";
    let choice_form_uuid = "cccccccc-cccc-4ccc-8ccc-ccccccccccc3";
    let auxiliary_form_uuid = "cccccccc-cccc-4ccc-8ccc-ccccccccccc4";
    let object_type_id = "11111111-1111-4111-8111-111111111111";
    let object_value_id = "11111111-1111-4111-8111-111111111112";
    let ref_type_id = "22222222-2222-4222-8222-222222222221";
    let ref_value_id = "22222222-2222-4222-8222-222222222222";
    let manager_type_id = "33333333-3333-4333-8333-333333333331";
    let manager_value_id = "33333333-3333-4333-8333-333333333332";
    let owner_fields = [
        "0",
        numerator_uuid,
        "1",
        "11",
        "0",
        "0",
        "1",
        "1",
        "0",
        "1",
        "0",
        "0",
        "0",
        object_form_uuid,
        list_form_uuid,
        choice_form_uuid,
        auxiliary_form_uuid,
        "00000000-0000-0000-0000-000000000000",
        "00000000-0000-0000-0000-000000000000",
        "0",
    ]
    .join(",");
    let document_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{40,{object_type_id},{object_value_id},{ref_type_id},{ref_value_id},\r\n{{0,\r\n{{3,\r\n{{1,0,{document_uuid}}},\"Invoice\",{{1,\"en\",\"Invoice\"}},\"\"}}\r\n}},{owner_fields},{manager_type_id},{manager_value_id}}}\r\n}}"
            )
            .as_bytes(),
        );
    let object_refs = BTreeMap::from([(
        numerator_uuid.to_string(),
        "DocumentNumerator.CompanyDocuments".to_string(),
    )]);
    let form_refs = BTreeMap::from([
        (
            object_form_uuid.to_string(),
            FormSourceReference {
                relative_path: PathBuf::from("Documents/Invoice/Forms/ObjectForm.xml"),
                kind: "Form",
            },
        ),
        (
            list_form_uuid.to_string(),
            FormSourceReference {
                relative_path: PathBuf::from("Documents/Invoice/Forms/ListForm.xml"),
                kind: "Form",
            },
        ),
        (
            choice_form_uuid.to_string(),
            FormSourceReference {
                relative_path: PathBuf::from("Documents/Invoice/Forms/ChoiceForm.xml"),
                kind: "Form",
            },
        ),
        (
            auxiliary_form_uuid.to_string(),
            FormSourceReference {
                relative_path: PathBuf::from("Documents/Invoice/Forms/AuxiliaryObjectForm.xml"),
                kind: "Form",
            },
        ),
    ]);

    let extracted = extract_metadata_source_xml_with_refs(
        &document_blob,
        document_uuid,
        &BTreeMap::new(),
        &object_refs,
        &BTreeMap::new(),
        &form_refs,
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_20,
    )
    .unwrap();
    let xml = String::from_utf8(extracted.xml).unwrap();

    assert!(xml.contains("<UseStandardCommands>false</UseStandardCommands>"));
    assert!(xml.contains("<Numerator>DocumentNumerator.CompanyDocuments</Numerator>"));
    assert!(xml.contains("<NumberType>String</NumberType>"));
    assert!(xml.contains("<NumberLength>11</NumberLength>"));
    assert!(xml.contains("<NumberAllowedLength>Fixed</NumberAllowedLength>"));
    assert!(xml.contains("<NumberPeriodicity>Year</NumberPeriodicity>"));
    assert!(xml.contains("<CheckUnique>true</CheckUnique>"));
    assert!(xml.contains("<Autonumbering>true</Autonumbering>"));
    assert!(
        xml.contains("<DefaultObjectForm>Document.Invoice.Form.ObjectForm</DefaultObjectForm>")
    );
    assert!(xml.contains("<DefaultListForm>Document.Invoice.Form.ListForm</DefaultListForm>"));
    assert!(
        xml.contains("<DefaultChoiceForm>Document.Invoice.Form.ChoiceForm</DefaultChoiceForm>")
    );
    assert!(xml.contains(
        "<AuxiliaryObjectForm>Document.Invoice.Form.AuxiliaryObjectForm</AuxiliaryObjectForm>"
    ));
    assert!(xml.contains("<AuxiliaryListForm/>"));
    assert!(xml.contains("<AuxiliaryChoiceForm/>"));
    assert!(
        xml.find("<UseStandardCommands>false</UseStandardCommands>")
            .unwrap()
            < xml.find("<StandardAttributes>").unwrap(),
        "{xml}"
    );
    assert!(
        xml.find("<StandardAttributes>").unwrap() < xml.find("<DefaultObjectForm>").unwrap(),
        "{xml}"
    );
}

