#[test]
fn extracts_data_processor_child_forms_and_templates_to_metadata_xml() {
    let data_processor_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let default_form_uuid = "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb";
    let auxiliary_form_uuid = "cccccccc-cccc-4ccc-8ccc-cccccccccccc";
    let extra_form_uuid = "dddddddd-dddd-4ddd-8ddd-dddddddddddd";
    let template_uuid = "eeeeeeee-eeee-4eee-8eee-eeeeeeeeeeee";
    let manager_type_id = "11111111-1111-4111-8111-111111111111";
    let manager_value_id = "22222222-2222-4222-8222-222222222222";
    let form_list_marker = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let data_processor_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{17,33333333-3333-4333-8333-333333333333,44444444-4444-4444-8444-444444444444,\r\n{{0,\r\n{{3,\r\n{{1,0,{data_processor_uuid}}},\"Loader\",{{1,\"en\",\"Loader\"}},\"\"}}\r\n}},{default_form_uuid},1,0,{manager_type_id},{manager_value_id},{auxiliary_form_uuid},{{0}},{{0}}}},{{{form_list_marker},2,{extra_form_uuid},{default_form_uuid}}},{{11111111-1111-4111-8111-111111111111,1,{template_uuid}}}\r\n}}"
            )
            .as_bytes(),
        );
    let form_refs = BTreeMap::from([
        (
            default_form_uuid.to_string(),
            FormSourceReference {
                relative_path: PathBuf::from("DataProcessors/Loader/Forms/MainForm.xml"),
                kind: "Form",
            },
        ),
        (
            auxiliary_form_uuid.to_string(),
            FormSourceReference {
                relative_path: PathBuf::from("DataProcessors/Loader/Forms/AssistantForm.xml"),
                kind: "Form",
            },
        ),
        (
            extra_form_uuid.to_string(),
            FormSourceReference {
                relative_path: PathBuf::from("DataProcessors/Loader/Forms/ExtraForm.xml"),
                kind: "Form",
            },
        ),
    ]);
    let template_refs = BTreeMap::from([(
        template_uuid.to_string(),
        TemplateSourceReference {
            relative_path: PathBuf::from("DataProcessors/Loader/Templates/Settings.xml"),
            kind: "Template",
            template_type: "TextDocument",
        },
    )]);

    for source_version in [
        InfobaseConfigSourceVersion::V2_20,
        InfobaseConfigSourceVersion::V2_21,
    ] {
        let extracted = extract_metadata_source_xml_with_refs(
            &data_processor_blob,
            data_processor_uuid,
            &BTreeMap::new(),
            &BTreeMap::new(),
            &BTreeMap::new(),
            &form_refs,
            &template_refs,
            &BTreeMap::new(),
            source_version,
        )
        .unwrap();
        let xml = String::from_utf8(extracted.xml).unwrap();

        assert!(xml.contains(&format!(r#"version="{}""#, source_version.as_str())));
        assert!(xml.contains("<ChildObjects>"));
        assert!(xml.contains("<Form>ExtraForm</Form>"));
        assert!(xml.contains("<Form>MainForm</Form>"));
        assert!(xml.contains("<Form>AssistantForm</Form>"));
        assert!(xml.contains("<Template>Settings</Template>"));
        assert!(
            xml.find("<Form>ExtraForm</Form>").unwrap()
                < xml.find("<Form>MainForm</Form>").unwrap()
        );
        assert!(
            xml.find("<Form>MainForm</Form>").unwrap()
                < xml.find("<Form>AssistantForm</Form>").unwrap()
        );
        assert!(
            xml.find("<Form>AssistantForm</Form>").unwrap()
                < xml.find("<Template>Settings</Template>").unwrap()
        );
        assert_eq!(xml.matches("<Form>MainForm</Form>").count(), 1);
        assert_eq!(xml.matches("<Template>Settings</Template>").count(), 1);
        assert!(
            xml.find("</Properties>").unwrap() < xml.find("<ChildObjects>").unwrap(),
            "{xml}"
        );
    }
}

#[test]
fn extracts_data_processor_child_command_properties_to_metadata_xml() {
    let data_processor_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
    let command_uuid = "bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb";
    let catalog_type_uuid = "cccccccc-cccc-4ccc-cccc-cccccccccccc";
    let manager_type_id = "11111111-1111-4111-8111-111111111111";
    let manager_value_id = "22222222-2222-4222-8222-222222222222";
    let data_processor_blob = deflate_for_test(
            format!(
                "{{1,\r\n{{17,33333333-3333-4333-8333-333333333333,44444444-4444-4444-8444-444444444444,\r\n\
{{0,\r\n{{3,\r\n{{1,0,{data_processor_uuid}}},\"Loader\",{{1,\"en\",\"Loader\"}},\"\"}}\r\n}},\
00000000-0000-0000-0000-000000000000,1,0,{manager_type_id},{manager_value_id},\
00000000-0000-0000-0000-000000000000,{{0}},{{0}}}},\
{{9,\r\n{{4,0,{{0}},\"\",-1,-1,1,0,\"\"}},3,\r\n{{1,\"en\",\"Load tip\"}},1,\r\n\
{{0,0,0}},0,\r\n{{1,aabb34e1-98c1-4bd0-bf7f-243f95437b44}},\r\n\
{{\"Pattern\",{{\"#\",{catalog_type_uuid}}}}},\r\n\
{{3,\r\n{{1,0,{command_uuid}}},\"Load\",{{1,\"en\",\"Load\"}},\"command comment\"}},1,0,0}}\r\n}}"
            )
            .as_bytes(),
        );
    let type_index = BTreeMap::from([(
        catalog_type_uuid.to_string(),
        "cfg:CatalogRef.Products".to_string(),
    )]);

    let extracted = extract_metadata_source_xml_with_refs(
        &data_processor_blob,
        data_processor_uuid,
        &type_index,
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        &BTreeMap::new(),
        InfobaseConfigSourceVersion::V2_21,
    )
    .unwrap();
    let xml = String::from_utf8(extracted.xml).unwrap();

    assert_eq!(
        extracted.relative_path,
        PathBuf::from("DataProcessors").join("Loader.xml")
    );
    assert!(xml.contains(r#"<Command uuid="bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb">"#));
    assert!(xml.contains("<Name>Load</Name>"));
    assert!(xml.contains("<Comment>command comment</Comment>"));
    assert!(xml.contains("<Group>ActionsPanelTools</Group>"));
    assert!(xml.contains("<CommandParameterType>"));
    assert!(xml.contains("<v8:Type>cfg:CatalogRef.Products</v8:Type>"));
    assert!(xml.contains("<ParameterUseMode>Single</ParameterUseMode>"));
    assert!(xml.contains("<ModifiesData>true</ModifiesData>"));
    assert!(xml.contains("<Representation>Auto</Representation>"));
    assert!(xml.contains("<ToolTip>"));
    assert!(xml.contains("<v8:content>Load tip</v8:content>"));
    assert!(xml.contains("<Picture/>"));
    assert!(xml.contains("<Shortcut/>"));
    assert!(xml.contains("<OnMainServerUnavalableBehavior>Auto</OnMainServerUnavalableBehavior>"));
    assert_eq!(xml.matches("<Command uuid=").count(), 1, "{xml}");
    assert!(xml.find("</Properties>").unwrap() < xml.find("<ChildObjects>").unwrap());
    assert!(xml.find("<Group>").unwrap() < xml.find("<CommandParameterType>").unwrap());
    assert!(xml.find("</CommandParameterType>").unwrap() < xml.find("<ParameterUseMode>").unwrap());
    assert!(xml.find("<ModifiesData>").unwrap() < xml.find("<Representation>").unwrap());
}

